  SPON_OP_LOADK = 3,
  SPON_OP_LOADKX = 4,
  SPON_OP_LOADFALSE = 5,
  SPON_OP_LFALSESKIP = 6,
  SPON_OP_LOADTRUE = 7,
  SPON_OP_LOADNIL = 8,
  SPON_OP_ADDI = 21,
